const input = ($json && typeof $json === 'object') ? $json : {};
const body = (input.body && typeof input.body === 'object') ? input.body : input;

const toText = (value) => {
  if (value === null || value === undefined) return '';
  if (Array.isArray(value)) {
    return value.map(toText).filter(Boolean).join(', ');
  }
  return String(value).replace(/\s+/g, ' ').trim();
};

const toLower = (value) => toText(value).toLowerCase();

const pick = (...keys) => {
  for (const key of keys) {
    if (Object.prototype.hasOwnProperty.call(body, key)) {
      const value = toText(body[key]);
      if (value) return value;
    }
  }
  return '';
};

const normalizeService = (value) => {
  const raw = toLower(value);
  if (!raw) return 'non-renseigne';
  if (raw.includes('site')) return 'site-web';
  if (raw.includes('identite') || raw.includes('logo') || raw.includes('artist')) return 'identite-visuelle';
  if (raw.includes('support') || raw.includes('print') || raw.includes('physique')) return 'support-physique';
  if (raw.includes('kit') || raw.includes('arpenteur')) return 'kit-arpenteur';
  return 'autre';
};

const normalizeBudget = (value) => {
  const raw = toLower(value);
  if (!raw) return 'non-renseigne';
  if (raw.includes('moins') || raw.includes('1000')) return 'moins-1000';
  if (raw.includes('3000') && raw.includes('1000')) return '1000-3000';
  if (raw.includes('6000') && raw.includes('3000')) return '3000-6000';
  if (raw.includes('plus') || raw.includes('6000')) return 'plus-6000';
  if (raw.includes('sais pas') || raw.includes('ne-sait-pas') || raw.includes('inconnu')) return 'ne-sait-pas';
  return 'autre';
};

const firstName = pick('prenom', 'firstName', 'firstname', 'first_name', 'name');
const lastName = pick('nom', 'lastName', 'lastname', 'last_name', 'surname');
const email = toLower(pick('email', 'mail', 'emailAddress', 'email_address'));
const phone = pick('telephone', 'phone', 'tel', 'mobile', 'numero');
const serviceRaw = pick('service', 'project_type', 'type', 'besoin', 'besoins');
const budgetRaw = pick('budget', 'budget_approximatif', 'price_range', 'priceRange');
const message = pick('message', 'note', 'notes', 'details', 'description');

const knownKeys = new Set([
  'prenom', 'firstName', 'firstname', 'first_name', 'name',
  'nom', 'lastName', 'lastname', 'last_name', 'surname',
  'email', 'mail', 'emailAddress', 'email_address',
  'telephone', 'phone', 'tel', 'mobile', 'numero',
  'service', 'project_type', 'type', 'besoin', 'besoins',
  'budget', 'budget_approximatif', 'price_range', 'priceRange',
  'message', 'note', 'notes', 'details', 'description'
]);

const extras = {};
Object.keys(body || {}).forEach((key) => {
  if (!knownKeys.has(key)) {
    extras[key] = toText(body[key]);
  }
});

const hasMeaningfulData = [firstName, lastName, email, phone, serviceRaw, budgetRaw, message].some(Boolean);
const receivedAt = new Date().toISOString();
const reference = `ct-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;

const responseBody = hasMeaningfulData
  ? {
      status: 'success',
      message: 'Merci, votre message est bien recu. Nous revenons vers vous sous 24h ouvrables.',
      data: { source: 'contact', reference, receivedAt }
    }
  : {
      status: 'error',
      message: 'Nous n\'avons pas pu lire correctement votre formulaire. Verifiez les champs principaux puis reessayez.',
      data: { source: 'contact', reference, receivedAt }
    };

return [{
  json: {
    source: 'contact',
    reference,
    receivedAt,
    normalizedPayload: {
      firstName,
      lastName,
      email,
      phone,
      service: normalizeService(serviceRaw),
      serviceRaw: toText(serviceRaw),
      budget: normalizeBudget(budgetRaw),
      budgetRaw: toText(budgetRaw),
      message,
      extras
    },
    rawPayload: body,
    responseCode: hasMeaningfulData ? 200 : 422,
    responseBody
  }
}];
